import{_ as s,o as a,c as e,Q as n}from"./chunks/framework.3daba8ea.js";const b=JSON.parse('{"title":"docker-compose","description":null,"frontmatter":{"lang":"zh-CN","title":"docker-compose","description":null},"headers":[],"relativePath":"doc/DevOps/Docker/Dockerfile/dockerfile.md","filePath":"packages/doc/src/DevOps/Docker/Dockerfile/dockerfile.md","lastUpdated":1702458087000}'),l={name:"doc/DevOps/Docker/Dockerfile/dockerfile.md"},p=n(`<h1 id="dockerfile" tabindex="-1">dockerfile <a class="header-anchor" href="#dockerfile" aria-label="Permalink to &quot;dockerfile&quot;">​</a></h1><h1 id="dockerfile-1" tabindex="-1">dockerfile <a class="header-anchor" href="#dockerfile-1" aria-label="Permalink to &quot;dockerfile&quot;">​</a></h1><h2 id="arg" tabindex="-1">ARG <a class="header-anchor" href="#arg" aria-label="Permalink to &quot;ARG&quot;">​</a></h2><h2 id="run" tabindex="-1">RUN <a class="header-anchor" href="#run" aria-label="Permalink to &quot;RUN&quot;">​</a></h2><h2 id="add" tabindex="-1">ADD <a class="header-anchor" href="#add" aria-label="Permalink to &quot;ADD&quot;">​</a></h2><p>复制文件 / 文件夹 可以从网络 / 本地复制</p><h2 id="copy" tabindex="-1">COPY <a class="header-anchor" href="#copy" aria-label="Permalink to &quot;COPY&quot;">​</a></h2><p>复制文件 / 文件夹 copy 仅从本地复制, 语义更明确, 推荐使用 copy</p><h2 id="workdir" tabindex="-1">WORKDIR <a class="header-anchor" href="#workdir" aria-label="Permalink to &quot;WORKDIR&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">1.Dockerfile中的WORKDIR指令用于指定容器的一个目录， 容器启动时执行的命令会在该目录下执行。</span></span>
<span class="line"><span style="color:#e1e4e8;">2.WORKDIR指令设置Dockerfile中的任何RUN，CMD，ENTRPOINT，COPY和ADD指令的工作目录。如果WORKDIR指 定的目录不存在，即使随后的指令没有用到这个目录，都会创建。</span></span>
<span class="line"><span style="color:#e1e4e8;">单个Dockerfile可以使用多次WORKFDIR。如果提供一个相对路径，当前的工作目录将于上个WORKDIR指令相关。</span></span>
<span class="line"><span style="color:#e1e4e8;">    </span></span>
<span class="line"><span style="color:#e1e4e8;">WORKDIR /a</span></span>
<span class="line"><span style="color:#e1e4e8;">WORKDIR b</span></span>
<span class="line"><span style="color:#e1e4e8;">WORKDIR c</span></span>
<span class="line"><span style="color:#e1e4e8;">RUN pwd</span></span>
<span class="line"><span style="color:#e1e4e8;">pwd命令的输出/a/b/c</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">WORKDIR可以解析之前由ENV设置的环境变量</span></span>
<span class="line"><span style="color:#e1e4e8;">ENV DIRPATH /path</span></span>
<span class="line"><span style="color:#e1e4e8;">WORKDIR $DIRPATH/$DIRNAME</span></span>
<span class="line"><span style="color:#e1e4e8;">RUN pwd</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">1.Dockerfile中的WORKDIR指令用于指定容器的一个目录， 容器启动时执行的命令会在该目录下执行。</span></span>
<span class="line"><span style="color:#24292e;">2.WORKDIR指令设置Dockerfile中的任何RUN，CMD，ENTRPOINT，COPY和ADD指令的工作目录。如果WORKDIR指 定的目录不存在，即使随后的指令没有用到这个目录，都会创建。</span></span>
<span class="line"><span style="color:#24292e;">单个Dockerfile可以使用多次WORKFDIR。如果提供一个相对路径，当前的工作目录将于上个WORKDIR指令相关。</span></span>
<span class="line"><span style="color:#24292e;">    </span></span>
<span class="line"><span style="color:#24292e;">WORKDIR /a</span></span>
<span class="line"><span style="color:#24292e;">WORKDIR b</span></span>
<span class="line"><span style="color:#24292e;">WORKDIR c</span></span>
<span class="line"><span style="color:#24292e;">RUN pwd</span></span>
<span class="line"><span style="color:#24292e;">pwd命令的输出/a/b/c</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">WORKDIR可以解析之前由ENV设置的环境变量</span></span>
<span class="line"><span style="color:#24292e;">ENV DIRPATH /path</span></span>
<span class="line"><span style="color:#24292e;">WORKDIR $DIRPATH/$DIRNAME</span></span>
<span class="line"><span style="color:#24292e;">RUN pwd</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><h2 id="volume" tabindex="-1">VOLUME <a class="header-anchor" href="#volume" aria-label="Permalink to &quot;VOLUME&quot;">​</a></h2><h2 id="hosts修改丢失问题" tabindex="-1">hosts修改丢失问题 <a class="header-anchor" href="#hosts修改丢失问题" aria-label="Permalink to &quot;hosts修改丢失问题&quot;">​</a></h2><p>RUN命令修改hosts文件，发现启动容器后不生效。因为容器创建会动态生成/etc/hosts，所以编译镜像期间修改无效。</p><ul><li>docker run --add-host</li><li>docker-compose中使用extra-hosts进行添加</li><li>容器启动脚本中使用shell动态添加</li></ul><h2 id="cmd" tabindex="-1">CMD <a class="header-anchor" href="#cmd" aria-label="Permalink to &quot;CMD&quot;">​</a></h2><ul><li>shell格式</li></ul><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">  CMD command  param1 param2</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">  CMD command  param1 param2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>exec格式</li></ul><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">CMD [&quot;command&quot;, &quot;param1&quot;, &quot;param1&quot;]</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">CMD [&quot;command&quot;, &quot;param1&quot;, &quot;param1&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>通常Docker中推荐使用exec格式语法，原因有二。</p><ul><li>shell格式语法下会通过/bin/sh -c来执行命令。</li><li>某些镜像甚至不包含Shell，致使shell格式下的命令无法被正常执行。但使用exec格式时，会无法获取环境变量的值。此时则可以考虑使用shell格式语法</li></ul><h2 id="entrypoint" tabindex="-1">ENTRYPOINT <a class="header-anchor" href="#entrypoint" aria-label="Permalink to &quot;ENTRYPOINT&quot;">​</a></h2><p><a href="https://zhuanlan.zhihu.com/p/548188679" target="_blank" rel="noreferrer">https://zhuanlan.zhihu.com/p/548188679</a> 该指令同样可以用于指定容器被启动时需要运行的命令。同理，其同样支持shell、exec两种形式的语法</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;"># shell格式</span></span>
<span class="line"><span style="color:#e1e4e8;">ENTRYPOINT command  param1 param2</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;"># exec格式</span></span>
<span class="line"><span style="color:#e1e4e8;">ENTRYPOINT [&quot;command&quot;, &quot;param1&quot;, &quot;param1&quot;]</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;"># shell格式</span></span>
<span class="line"><span style="color:#24292e;">ENTRYPOINT command  param1 param2</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;"># exec格式</span></span>
<span class="line"><span style="color:#24292e;">ENTRYPOINT [&quot;command&quot;, &quot;param1&quot;, &quot;param1&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>对于ENTRYPOINT指令而言，Docker中同样推荐使用exec格式语法，理由与CMD指令同理。 ENTRYPOINT指令 所设置命令、参数可被 docker run命令行参数中指定要运行的命令 覆盖, 但需要使用 --entrypoint 选项进行显式覆盖。否则将会忽略命令行参数</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;"># 错误方式</span></span>
<span class="line"><span style="color:#e1e4e8;">docker run --name demo3B --rm -it demo3:test ifconfig</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;"># 正确方式</span></span>
<span class="line"><span style="color:#e1e4e8;">docker run --name demo3C --rm -it --entrypoint ifconfig demo3:test</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;"># 错误方式</span></span>
<span class="line"><span style="color:#24292e;">docker run --name demo3B --rm -it demo3:test ifconfig</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;"># 正确方式</span></span>
<span class="line"><span style="color:#24292e;">docker run --name demo3C --rm -it --entrypoint ifconfig demo3:test</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div>`,26),o=[p];function r(c,i,t,d,u,h){return a(),e("div",null,o)}const k=s(l,[["render",r]]);export{b as __pageData,k as default};
